// src/components/DashboardRecepcao.jsx
import React, { useEffect, useRef, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import Modal from "./components/Modal";
import FormAgendamento from "./components/FormAgendamento";
import { useAuth } from "./context/AuthContext";

export default function DashboardRecepcao() {
  const [periodos, setPeriodos] = useState([]);
  const [selectedPeriodo, setSelectedPeriodo] = useState(null);
  const [disciplinas, setDisciplinas] = useState([]);
  const [disciplinaSelecionada, setDisciplinaSelecionada] = useState(null);
  const [agendamentosFiltrados, setAgendamentosFiltrados] = useState([]);
  const [busca, setBusca] = useState("");
  const [filtroData, setFiltroData] = useState("");
  const [filtroHora, setFiltroHora] = useState("");
  const [mostrarModal, setMostrarModal] = useState(false);
  const [agendamentoEditando, setAgendamentoEditando] = useState(null);
  const [swipedId, setSwipedId] = useState(null);
  const [menuOpenId, setMenuOpenId] = useState(null);

  const touchStartX = useRef(0);
  const dataInputRef = useRef();
  const horaInputRef = useRef();
  const { user } = useAuth();
  const navigate = useNavigate();

  const STATUS_LABELS = { Novo: "Novo", Retorno: "Retorno", Solicitado: "Solicitado" };
  const STATUS_COLORS = {
    Novo: "bg-[#2FA74E] text-white",
    Retorno: "bg-[#FEC139] text-[#555555]",
    Solicitado: "bg-[#DA3648] text-white",
  };

  const cardColors = [
    "bg-[#5956D6]","bg-[#2B8FF2]","bg-[#ECAD21]","bg-[#03A400]","bg-[#DA5D5C]",
    "bg-[#926AFF]","bg-[#568BEF]","bg-[#ECAD21]","bg-[#FF7FAF]","bg-[#926AFF]","bg-[#009AF3]",
  ];

  // Carrega períodos e disciplinas
  useEffect(() => {
    axios.get("/api/periodos").then(res => setPeriodos(res.data)).catch(() => {});
    axios.get("/api/disciplinas").then(res => setDisciplinas(res.data)).catch(() => {});
  }, []);

  function buscarAgendamentosDaDisciplina(disc) {
    setDisciplinaSelecionada(disc);
    axios.get(`/api/agendamentos?disciplinaId=${disc.id}`)
      .then(res => setAgendamentosFiltrados(res.data))
      .catch(() => {});
  }

  const hoje = new Date(); hoje.setHours(0,0,0,0);

  const agendamentosExibidos = agendamentosFiltrados.filter(a => {
    const t = busca.toLowerCase();
    const campos = [a.operadorNome, a.auxiliarNome, a.periodo_nome, a.pacienteNome, a.status]
      .map(x=>x?x.toLowerCase():"");
    const okTexto = campos.some(c=>c.includes(t));
    const okData = filtroData? a.data?.startsWith(filtroData): true;
    const okHora = filtroHora? a.hora?.startsWith(filtroHora): true;
    return okTexto && okData && okHora;
  });

  const handleImprimir = () => {
    navigate("/print-agendamentos", { state: { disciplinaId: disciplinaSelecionada.id, disciplinaNome: disciplinaSelecionada.nome, filtros: { busca, filtroData, filtroHora } } });
  };

  const handleDeletarAgendamento = id => {
    if (!window.confirm("Tem certeza?")) return;
    axios.delete(`/api/agendamentos/${id}`)
      .then(()=> setAgendamentosFiltrados(cur=>cur.filter(a=>a.id!==id)))
      .catch(()=>{});
  };

  const handleEditarAgendamento = ag => { setAgendamentoEditando(ag); setMostrarModal(true); };
  const handleSalvarAgendamentoEditado = () => { buscarAgendamentosDaDisciplina(disciplinaSelecionada); setMostrarModal(false); };
  const handleCancelarEdicao = () => setMostrarModal(false);

  function Tooltip({ text }) { return <span className="absolute left-1/2 -translate-x-1/2 -top-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 z-50 opacity-0 group-hover:opacity-100 transition">{text}</span>; }
  const handleDataClick = ()=> dataInputRef.current?.showPicker ? dataInputRef.current.showPicker() : dataInputRef.current.click();
  const handleHoraClick = ()=> horaInputRef.current?.showPicker? horaInputRef.current.showPicker(): horaInputRef.current.click();

  const disciplinasVisiveis = selectedPeriodo ? disciplinas.filter(d=>d.periodo_id===selectedPeriodo) : disciplinas;

  const formatDateTime = dtStr => dtStr? new Date(dtStr).toLocaleString() : '-';

  return (
    <div className="mx-auto py-8 px-4">
      <h1 className="text-2xl font-bold mb-6 text-[#1d3557]">Períodos</h1>
      <div className="flex flex-wrap gap-2 mb-8">
        {periodos.map(p=>(<button key={p.id} onClick={()=>{setSelectedPeriodo(p.id);setDisciplinaSelecionada(null);}} className={`px-4 py-2 rounded-full border transition ${selectedPeriodo===p.id?"bg-[#3172C0] text-white":"bg-white text-gray-700 border-gray-300 hover:bg-[#3172C0] hover:text-white"}`}>{p.nome}</button>))}
        {selectedPeriodo&&<button onClick={()=>setSelectedPeriodo(null)} className="px-2 py-2 rounded-full text-red-600 hover:bg-red-100">Limpar</button>}
      </div>
      <h1 className="text-2xl font-bold mb-6 text-[#1d3557]">Disciplinas</h1>
      <div className="flex flex-wrap gap-2 mb-8">
        {disciplinasVisiveis.map((disc,idx)=>(<button key={disc.id} onClick={()=>buscarAgendamentosDaDisciplina(disc)} className={`min-w-[150px] flex-1 rounded-2xl px-6 py-8 text-left border-2 transition ${disciplinaSelecionada?.id===disc.id?"border-[#F3F3F3] bg-[#3172C0] text-white":"border-transparent hover:border-[#3172C0] hover:bg-[#3172C0] ${cardColors[idx%cardColors.length]} text-white"}`}><div className="font-bold text-lg mb-1">{disc.nome}</div><div className="text-sm">{disc.periodo_nome} {disc.turno}</div></button>))}
      </div>

      {disciplinaSelecionada && (
        <div className="bg-white rounded-2xl">
          <h2 className="text-lg font-semibold px-4 pt-6 pb-2">Agendamentos de <span className="text-[#3172C0]">{disciplinaSelecionada.nome}</span></h2>
          <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pt-0 pb-4 rounded-2xl bg-white mb-6">
            {/* filtros unchanged */}
          </div>

          <h2 className="text-xl font-semibold px-4 py-2">Lista de Agendamentos</h2>
          <div className="overflow-x-auto">
            <div className="mt-2 space-y-3">
              {agendamentosExibidos.map(ag=>(<React.Fragment key={ag.id}>
                {/* MOBILE CARD */}
                <div className="block md:hidden relative overflow-hidden rounded-xl shadow-sm" onTouchStart={e=>{touchStartX.current=e.touches[0].clientX;}} onTouchEnd={e=>{const dx=e.changedTouches[0].clientX-touchStartX.current; if(dx<-50) setSwipedId(ag.id); else if(dx>50) setSwipedId(null);}}>
                  <button onClick={()=>setMenuOpenId(menuOpenId===ag.id?null:ag.id)} className="absolute top-2 right-2 p-1 text-gray-500 hover:text-gray-700">⋮</button>
                  <div className={`bg-white p-4 transform transition-transform ${swipedId===ag.id?"-translate-x-24":""}`}> 
                    <div className="flex items-center mb-3"> 
                      <div className="w-10 h-10 rounded-full bg-blue-200 flex items-center justify-center text-white font-semibold mr-3">{ag.pacienteNome?.charAt(0).toUpperCase()||"?"}</div>
                      <div className="flex-1"> 
                        <div className="text-sm text-gray-500">#{ag.id} • {ag.operadorNome||"-"}</div>
                        <div className="font-medium text-gray-800 truncate">{disciplinaSelecionada.nome}</div>
                      </div>
                      <span className="px-3 py-1 rounded-full text-xs font-semibold {STATUS_COLORS[ag.status]}">{ag.status}</span>
                    </div>
                    <div className="text-gray-600 text-sm mb-3">Incluído em: {formatDateTime(ag.createdAt)}</div>
                    <div className="text-gray-600 text-sm mb-3">Paciente: {ag.pacienteNome||"-"}</div>
                    <div className="flex justify-between text-gray-600 text-sm"><span>{ag.telefone||"-"}</span><span>{ag.data.slice(0,10).split("-").reverse().join("/")}</span><span>{ag.hora||"-"}</span></div>
                  </div>
                  {menuOpenId===ag.id&&(<div className="absolute top-12 right-2 bg-white border rounded shadow-md flex flex-col"><button onClick={()=>{handleEditarAgendamento(ag);setMenuOpenId(null);}} className="px-4 py-2 text-left hover:bg-gray-100">Editar</button><button onClick={()=>{handleDeletarAgendamento(ag.id);setMenuOpenId(null);}} className="px-4 py-2 text-left hover:bg-gray-100">Deletar</button></div>)}
                </div>

                {/* DESKTOP GRID */}
                <div className="hidden md:grid md:grid-cols-9 gap-y-1 gap-x-4 items-center bg-gray-50 rounded-xl px-4 md:px-5 py-2 shadow-sm hover:bg-gray-100 transition">
                  <div className="font-medium text-gray-800 truncate">{ag.operadorNome||"-"}</div>
                  <div className="text-gray-800 truncate">{ag.auxiliarNome||"-"}</div>
                  <div className="text-gray-800 truncate">{disciplinaSelecionada.nome}</div>
                  <div className="text-gray-800 truncate">{ag.pacienteNome||"-"}</div>
                  <div className="text-gray-500 truncate">{ag.telefone||"-"}</div>
                  <div className="text-gray-500 truncate">{formatDateTime(ag.createdAt)}</div>
                  <div className="text-gray-800 truncate">{ag.data.slice(0,10).split("-").reverse().join("/")}</div>
                  <div className="text-gray-800 truncate">{ag.hora||"-"}</div>
                  <div className="relative flex justify-end w-full">
                    <button onClick={()=>setMenuOpenId(menuOpenId===ag.id?null:ag.id)} className="p-1 text-gray-500 hover:text-gray-700">⋮</button>
                    {menuOpenId===ag.id&&(<div className="absolute top-6 right-0 bg-white border rounded shadow-md flex flex-col"><button onClick={()=>{handleEditarAgendamento(ag);setMenuOpenId(null);}} className="px-4 py-2 text-left hover:bg-gray-100">Editar</button><button onClick={()=>{handleDeletarAgendamento(ag.id);setMenuOpenId(null);}} className="px-4 py-2 text-left hover:bg-gray-100">Deletar</button></div>)}
                  </div>
                </div>
              </React.Fragment>))}
            </div>
          </div>

          {/* Modal de edição */}
          {mostrarModal && (
            <Modal isOpen={mostrarModal} onRequestClose={handleCancelarEdicao}>
              <FormAgendamento agendamentoEditando={agendamentoEditando} onNovoAgendamento={handleSalvarAgendamentoEditado} onFimEdicao={handleCancelarEdicao} />
            </Modal>
          )}
        </div>
      )}
    </div>
  );
}
